#include<iostream>
using namespace std;
bool visit[30];
bool flag[30];
int main()
{
	string str;
	cin >> str;
	for(int i = 0; i < str.size(); i++)
	{
		if(visit[str[i] - 'a'])
		{
			flag[str[i] - 'a'] = true;
		}
		visit[str[i] - 'a'] = true;
	}
	for(int i = 0; i < str.size(); i++)
	{
		if(!flag[str[i] - 'a'])
		{
			cout << str[i];
			return 0;
		}
	}
	cout << "no";
	return 0;
}
